import { useSignAndExecuteTransaction } from '@iota/dapp-kit';
import { useState } from 'react';
import { Transaction } from '@iota/iota-sdk/transactions';
import { FormRow } from './MoveFormsStyleHelper.tsx';
import { moveTarget, submitTx } from './MoveFormsTransactionHelper.tsx';

export function UpdateDataTypeForm({ address }: { address: string }) {
  const { mutate: signAndExecuteTransaction } = useSignAndExecuteTransaction();
  const [digest, setDigest] = useState('');

  const [form, setForm] = useState({
    container: '',
    dataType: '',
    externalId: '',
    name: '',
    description: '',
    content: '',
    schemas: '',
    externalIndex: 0,
  });

  const submit = () => {
    const tx = new Transaction();

    tx.moveCall({
      target: moveTarget('update_data_type'),
      arguments: [
        tx.object(form.container),
        tx.object(form.dataType),
        tx.pure.string(form.externalId),
        tx.pure.string(form.name),
        tx.pure.string(form.description),
        tx.pure.string(form.content),
        tx.pure.string(form.schemas),
        tx.pure.u128(form.externalIndex),
      ],
    });

    submitTx(signAndExecuteTransaction, tx, address, setDigest);
  };

  return (
    <div className="d-flex justify-content-center mt-4">
      <div className="w-100" style={{ maxWidth: 560 }}>
        <h5 className="text-center mb-4">Update Data Type</h5>

        <FormRow label="Container ID">
          <input
            className="form-control form-control-sm rounded-3"
            placeholder="0x..."
            value={form.container}
            onChange={(e) => setForm({ ...form, container: e.target.value })}
          />
        </FormRow>

        <FormRow label="Data Type ID">
          <input
            className="form-control form-control-sm rounded-3"
            placeholder="0x..."
            value={form.dataType}
            onChange={(e) => setForm({ ...form, dataType: e.target.value })}
          />
        </FormRow>

        <FormRow label="New External ID">
          <input
            className="form-control form-control-sm rounded-3"
            value={form.externalId}
            onChange={(e) => setForm({ ...form, externalId: e.target.value })}
          />
        </FormRow>

        <FormRow label="New Name">
          <input
            className="form-control form-control-sm rounded-3"
            value={form.name}
            onChange={(e) => setForm({ ...form, name: e.target.value })}
          />
        </FormRow>

        <FormRow label="New Description">
          <input
            className="form-control form-control-sm rounded-3"
            value={form.description}
            onChange={(e) => setForm({ ...form, description: e.target.value })}
          />
        </FormRow>

        <FormRow label="New Content">
          <textarea
            className="form-control form-control-sm rounded-3"
            rows={3}
            value={form.content}
            onChange={(e) => setForm({ ...form, content: e.target.value })}
          />
        </FormRow>

        <FormRow label="New Schemas">
          <textarea
            className="form-control form-control-sm rounded-3"
            rows={3}
            value={form.schemas}
            onChange={(e) => setForm({ ...form, schemas: e.target.value })}
          />
        </FormRow>

        <FormRow label="New External Index">
          <input
            type="number"
            className="form-control form-control-sm rounded-3"
            value={form.externalIndex}
            onChange={(e) =>
              setForm({ ...form, externalIndex: Number(e.target.value) })
            }
          />
        </FormRow>

        <div className="text-center mt-4">
          <button
            className="btn btn-outline-primary btn-sm px-4"
            onClick={submit}
          >
            Update Data Type
          </button>
        </div>

        {digest && (
          <div className="text-center small mt-3">
            Digest: {digest}
          </div>
        )}
      </div>
    </div>
  );
}
